// Terminal commands:

// npm start - runs the "start" script
// npm test - runs the "test" script
// npm run dev - runs the "dev" script

// Chain scripts: "pre" and "post" hooks
// npm run build
// 1. Runs "prebuild" (if defined)
// 2. Runs "build"
// 3. Runs "postbuild" (if defined)

// Pass arguments:
// npm run test -- --grep "auth"
// The -- passes remaining args to the script

// Environment variables in scripts:
// "start:prod": "NODE_ENV=production node app.js"
// Cross-platform: use cross-env package
// "start:prod": "cross-env NODE_ENV=production node app.js"

// npm bin directory in scripts:
// npm adds node_modules/.bin to PATH during scripts
// So you can run:
// "test": "mocha tests/"  // without global mocha install

// Commonly used in scripts:
// "clean": "rimraf dist/"
// "build": "mkdirp dist && babel src -d dist"
// "dev": "nodemon src/index.js"
// "typecheck": "tsc --noEmit"

// npm run env - shows all env vars available to scripts
// $npm_package_name = package name
// $npm_package_version = package version
// These are available as environment variables

// Clean install (for CI/CD)
// npm ci
// - Deletes node_modules
// - Installs from package-lock.json only
// - Fails if lockfile is missing or out of sync
// - Faster than npm install (~2x)

// Regular install (for development)
// npm install
// - Reads package.json
// - Updates package-lock.json if needed
// - Installs from registry

// Install specific version
// npm install lodash@4.17.21

// Install latest version
// npm install lodash@latest

// Install globally
// npm install -g nodemon

// Install as dev dependency
// npm install -D mocha

// Install as optional dependency
// npm install -O csv-parser

// Install without saving to package.json
// npm install --no-save temp-package

// Install from a git repository
// npm install https://github.com/user/repo.git

// Install from a local path
// npm install ./local-package

// Audit for vulnerabilities
// npm audit

// Auto-fix vulnerabilities
// npm audit fix

// Show outdated packages
// npm outdated

// 1. Create package.json
// npm init -y

// 2. Login to npm
// npm login

// 3. Configure package.json for publishing
{
  "name": "@my-scope/hello-world",
  "version": "1.0.0",
  "description": "A simple hello world package",
  "main": "index.js",
  "files": ["index.js", "README.md"],
  "keywords": ["hello", "world", "demo"],
  "license": "MIT",
  "repository": {
    "type": "git",
    "url": "git+https://github.com/user/hello-world.git"
  },
  "bugs": {
    "url": "https://github.com/user/hello-world/issues"
  },
  "homepage": "https://github.com/user/hello-world#readme"
}

// 4. Create .npmignore (or use .gitignore)
// .npmignore:
// tests/
// src/
// .git/

// 5. Bump version
// npm version patch  // 1.0.0 -> 1.0.1
// npm version minor  // 1.0.1 -> 1.1.0
// npm version major  // 1.1.0 -> 2.0.0

// 6. Publish
// npm publish

// For scoped packages (public):
// npm publish --access public

// 7. Manage distribution tags
// npm dist-tag add @my-scope/hello-world@1.0.0 beta
// npm dist-tag ls @my-scope/hello-world

// 8. Deprecate a version
// npm deprecate @my-scope/hello-world@"1.0.0" "Critical bug fixed in 1.0.1"

// Root package.json
{
  "private": true,
  "workspaces": [
    "packages/*",
    "apps/*"
  ],
  "scripts": {
    "test": "npm run test --workspaces",
    "build": "npm run build --workspace=@myapp/core",
    "lint": "npx eslint packages/*/src"
  }
}

// Directory structure:
// root/
//   package.json (workspaces config)
//   packages/
//     core/
//       package.json (@myapp/core)
//     utils/
//       package.json (@myapp/utils)
//   apps/
//     web/
//       package.json (@myapp/web, depends on @myapp/core)

// Install all workspace dependencies:
// npm install (from root)

// Run script in specific workspace:
// npm run build --workspace=packages/core

// Run script in all workspaces:
// npm test --workspaces

// Add dependency to a specific workspace:
// npm install lodash --workspace=packages/core

// Workspace benefits:
// - Shared node_modules (hoisted dependencies)
// - Local packages are symlinked
// - Single lockfile
// - Cross-package script coordination
// - Consistent versioning across packages
